namespace Rocks.Exceptions;

/// <summary>
/// Thrown when a mocked method has the <see cref="System.Diagnostics.CodeAnalysis.DoesNotReturnAttribute"/> on it
/// to prevent the method from returning.
/// </summary>
/// <remarks>
/// This type is designed to be used from code generated by Rocks,
/// and is not intended for general use. Please refrain from
/// referencing it for any other purposes, as its implementation may change.
/// </remarks>
[Serializable]
public sealed class DoesNotReturnException
	: Exception
{ }